oldWay:
/* Spread items using floats — a common nav pattern */
.nav {
  overflow: hidden;
}
.item {
  float: left;
}
.item:last-child {
  float: right;
}

startingCSS:
.container {
  display: flex;
  background: #1e2235;
  padding: 0.75rem 1rem;
  border-radius: 8px;
}

.item {
  color: #e2e8f0;
  text-decoration: none;
  padding: 0.5rem 1rem;
  border-radius: 4px;
  font-weight: 500;
  transition: background 0.15s;
}

.item:hover {
  background: rgba(168, 85, 247, 0.2);
}
